    // 2. Palyvos, J.A., 2008. A survey of wind convection coefficient correlations for building
    //     envelope energy systems' modeling. Applied Thermal Engineering 28 (2008) 801-808. Elsevier.

    return 5.8 + 3.8 * WindAtZ;
}

