def VB_SLAT_RADIUS_RATIO(W: Float64, C: Float64) -> Float64:
    if C <= 0.0 or W <= 0.0:
        return 0.0
    var CX: Float64 = min(C, W / 2.001)
    return 2.0 * W * CX / (CX * CX + W * W / 4)

